import numpy as np

def loss_and_grad(w):
    # L(w) = (w - 5)^2,  dL/dw = 2(w - 5)
    return (w - 5) ** 2, 2 * (w - 5)

w = 0.0
eta = 0.1
for step in range(20):
    L, g = loss_and_grad(w)
    w = w - eta * g          # theta <- theta - eta * grad L
    print(f"step {step:2d}  w={w:.4f}  L={L:.4f}")
